championship_records = {
    'men_singles': {'Viktor Pfeifer': 9},
    'women_singles': {'Regine Heitzer': 7},
    'pair_skating': {'Miriam Ziegler': 8, 'Severin Kiefer': 11},
    'ice_dance': {'Dmitri Matsjuk': 8}
}

def find_champion(discipline):
    if discipline in championship_records:
        champions = championship_records[discipline]
        return max(champions.items(), key=lambda x: x[1])
    return None

# Example usage:
champion = find_champion('pair_skating')
print(f"{champion[0]} has the most titles with {champion[1]} championships.")
